VALUES
  ('social-worker-moex-06880', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '新手在帶領團體工作時，下列情況中何者錯誤？', '["理解成員背景資料，以便控制團體走向", "溫習團體發展初期的動力特徵，以為因應", "熟悉團體方案規劃的流程，並做好應變的備案", "沉澱凝思，放鬆筋骨，準備上場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06881', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某社區老、中、青全力投入，社區幹部有活力，社區凝聚力強，陣頭、技藝團隊、各種文化傳承活動多， 生活方式很豐富，居民和樂融融…。請問該社區符合社區發展指定工作項目的那一項？', '["生產福利建設", "精神倫理建設", "公共設施建設", "社會福利社區化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06882', 'social-worker', 'social-worker-moex-102-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '推動福利社區化的方式可以「由社區提供照顧」（care by the community），其意涵為？', '["由社區內小型福利機構所提供的照顧", "由社區內日間照顧中心所提供的照顧", "由社區內非正式支援網絡或民間志願團體所提供的照顧", "由社區內醫療衛生單位所提供的照顧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "6dd28d6f1360", "answer_pdf_sha1": "ff4bc151c740", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06883', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關社會工作研究方法，下列敘述何者錯誤？', '["量化研究傾向以解釋變項間之關係為主，而質性研究偏向以描述和探索某現象為主", "無論是量化研究或是質性研究，其研究設計邏輯差不多，都是社工界常用之研究方法", "量化研究採局外人取向（outsider’s view），重在以理論的觀點解釋當事者之處境與行為，而質性研究 則採局內人取向（insider’s view），重在以當事人的觀點解釋當事者之處境與行為", "量化研究以演繹法（deductive method）為基礎，而質性研究以歸納法（inductive method）為基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06884', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關個案研究之敘述，何者錯誤？', '["個案研究是對特定對象所做之關注", "個案研究重在看到研究對象之獨特性，因而必須深入了解被研究者之情境及事件背後所代表之意義", "對於研究結果，應該是厚實描述（thick description）及豐富的", "只能研究一個個案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06885', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社工師想研究何項家庭因素最能解釋新住民家庭子女之生活適應程度，這些可能的因素包括親子關係、 家庭經濟及父母管教態度。那麼其該採用何種統計方法較為適當？', '["卡方檢定", "多元迴歸", "t-test", "變異數分析"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06886', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者為正確的研究假設陳述？', '["提供密集性服務，可以預防中輟生之逃學機率", "中途之家是國家的基礎", "遊民與天氣", "中輟生都應該每天上學"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06887', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關「單案研究設計」敘述，何者正確？', '["可以概推到其他的個案", "無法發現新的理論", "可以控制歷史因素", "外在效度差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06888', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關理論及操作化，何者敘述錯誤？', '["理論又稱theory，操作化又稱為operationalization", "理論乃是一組互相關聯的命題所組成的知識整體", "理論中的命題是不能被證實的", "操作化乃是針對理論的概念（concept），賦予明確的指標，使之成為變項（variable）的過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06889', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小華的碩士論文是研究「高職建教生家庭結構與中途輟學因素之關係探討」，請問高職建教生之輟學因 素是屬於下列何種測量尺度？', '["等距量數（interval measure）", "順序量數（ordinal measure）", "等比量數（ratio measure）", "名義量數（nominal measure）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
